INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (1, 'en', 'Barilla Pasta 500g', 'Premium Italian pasta', 'Made from 100% durum wheat semolina. Cooking time: 8-10 minutes. Perfect for bolognese, carbonara, and pesto dishes. Bronze die cut for better sauce adhesion.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (2, 'en', 'Basmati Rice 1kg', 'Fragrant long-grain basmati rice', 'Aged for 12 months for extra flavor. Originating from the foothills of the Himalayas. Each grain cooks up fluffy and separate. Ideal for curries, pilafs, and stir-fries.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (3, 'en', 'Extra Virgin Olive Oil 1L', 'First cold press extra virgin olive oil', 'Single origin olive oil from Mediterranean groves. Acidity below 0.8%. Rich in antioxidants and polyphenols. Perfect for salads, bread dipping, and finishing dishes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (4, 'en', 'Unsalted Butter 250g', 'Creamy churned unsalted butter', 'Traditional churned butter made from pasteurized cream. 82% fat content. Ideal for baking, cooking, and spreading. Produced in Normandy, France.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (5, 'en', 'All-Purpose Flour T55 1kg', 'All-purpose wheat flour', 'Type 55 wheat flour, versatile for all uses. Perfect for bread, pastries, sauces, and batters. Ash content 0.50-0.60%. Milled from French wheat.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (6, 'en', 'Granulated Sugar 1kg', 'White granulated sugar', 'Pure white cane sugar, fine granulation. Perfect for baking, hot drinks, and desserts. Dissolves quickly and evenly.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (7, 'en', 'Guérande Sea Salt 250g', 'Hand-harvested sea salt', 'Harvested by hand from the salt marshes of Guérande, Brittany. Naturally grey, rich in minerals and trace elements. Unrefined and unwashed. A staple of French gastronomy.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (8, 'en', 'Organic Free-Range Eggs x12', 'Organic free-range eggs from outdoor hens', 'From hens raised outdoors with access to organic feed. No antibiotics or hormones. Rich yellow yolks with superior taste. Category A, size M/L.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (9, 'en', 'Evian 1.5L', 'Natural mineral water from the Alps', 'Sourced from the French Alps, naturally filtered through glacial rocks for over 15 years. Balanced mineral composition. pH 7.2. Low sodium content.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (10, 'en', 'Perrier 1L', 'Natural sparkling mineral water', 'Naturally carbonated at the source in Vergèze, France since 1898. Fine, persistent bubbles. Zero calories. The iconic green bottle.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (11, 'en', 'Tropicana Orange Juice 1L', 'Pure squeezed orange juice, no pulp', '100% pure squeezed orange juice, not from concentrate. No added sugar. Rich in vitamin C. Pasteurized for freshness.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (12, 'en', 'Coca-Cola 1.5L', 'Refreshing carbonated drink', 'The original cola flavor since 1886. Served ice-cold for the perfect refreshment. Contains caffeine. Family size 1.5L bottle.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (13, 'en', 'Artisan Lemonade 75cl', 'Artisan lemonade with Menton lemons', 'Handcrafted lemonade using Menton lemons from the French Riviera. Lightly sparkling, natural ingredients only. No artificial colors or preservatives.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (14, 'en', 'Cristaline Spring Water x6', 'Pack of 6 spring water bottles 1.5L', 'Natural spring water, light and refreshing. Convenient multipack for the whole family. Low mineral content, suitable for everyday hydration.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (15, 'en', 'Lipton Ice Tea Peach 1.5L', 'Peach flavored iced tea', 'Refreshing iced tea with natural peach flavor. Made with real tea leaves. Low in calories. Best served chilled.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (16, 'en', 'Bordeaux Red 2020', 'AOC Bordeaux red wine, fruity and balanced', 'A blend of Merlot and Cabernet Sauvignon from the right bank of Bordeaux. Aromas of red berries and vanilla. Pairs well with red meat, cheese, and charcuterie. Serve at 16-18°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (17, 'en', 'Côtes du Rhône 2021', 'AOC red wine with spicy and fruity notes', 'Grenache-Syrah blend from the southern Rhône Valley. Notes of blackberry, pepper, and garrigue herbs. Full-bodied with smooth tannins. Serve at 16°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (18, 'en', 'Champagne Moët & Chandon', 'Brut Impérial champagne, fine bubbles', 'The iconic Moët Impérial, created in 1869. Blend of Pinot Noir, Chardonnay, and Pinot Meunier. Fine persistent bubbles, notes of citrus and brioche. Perfect for celebrations.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (19, 'en', 'Leffe Blonde 75cl', 'Blonde abbey beer, smooth and fruity', 'Belgian abbey beer brewed since 1240. 6.6% ABV. Notes of vanilla, clove, and ripe banana. Serve at 5-6°C in a chalice glass.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (20, 'en', 'Jameson Whiskey 70cl', 'Triple distilled Irish whiskey, smooth and round', 'Triple distilled and aged in oak barrels for a minimum of 4 years. Smooth, light, and perfectly balanced. Notes of vanilla, toasted wood, and sherry. 40% ABV.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (21, 'en', 'Provence Rosé 2023', 'AOP Côtes de Provence rosé, fresh and light', 'Pale salmon pink color. Aromas of peach, citrus, and white flowers. Crisp and refreshing on the palate. Perfect with seafood, salads, and summer dishes. Serve at 8-10°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (22, 'en', 'Burgundy Pinot Noir 2019', 'AOC Burgundy red wine, elegant and delicate', '100% Pinot Noir from the Côte de Beaune. Aromas of cherry, raspberry, and subtle oak. Silky tannins with a long finish. Pairs with poultry, mushrooms, and light cheeses.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (23, 'en', 'Black Leather Jacket', 'Genuine leather jacket, slim fit', 'Crafted from premium lamb leather. YKK zippers, polyester lining. Slim fit silhouette. Two exterior pockets, one interior pocket. Leather will develop a beautiful patina over time.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (24, 'en', 'Levi''s Slim Blue Jeans', 'Levi''s comfortable stretch slim jeans, washed blue', '98% cotton, 2% elastane for comfort stretch. Slim fit through hip and thigh. Five-pocket styling. Machine washable at 30°C. Faded blue wash finish.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (25, 'en', 'White Cotton T-shirt', '100% organic cotton t-shirt, straight cut', 'GOTS certified organic cotton. 180g/m² weight for durability. Reinforced collar that won''t stretch. Pre-shrunk fabric. Available in sizes XS to XXL.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (26, 'en', 'Grey Wool Sweater', 'Warm and soft merino wool sweater', '100% Australian merino wool, 19.5 micron. Natural temperature regulation. Crew neck, ribbed cuffs and hem. Hand wash or dry clean recommended. Anti-pilling treatment.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (27, 'en', 'Linen Shirt', 'Natural linen shirt, ideal for summer', '100% European flax linen. Breathable and moisture-wicking. Regular fit with button-down collar. Gets softer with each wash. Perfect for warm weather.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (28, 'en', 'Schott Brown Leather Bomber', 'Schott nubuck leather bomber jacket, aviator style', 'Premium nubuck leather, aviator-inspired design. Shearling collar. Front zip closure with snap button storm flap. Two flap pockets. Fully lined.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (29, 'en', 'Floral Summer Dress', 'Light floral print dress, flowing fit', '100% viscose for a fluid drape. All-over floral print. V-neck with adjustable straps. Midi length. Machine washable. Perfect for beach and garden parties.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (30, 'en', 'Winter Coat', 'Long wool blend coat, warm and elegant', '70% wool, 30% polyester blend. Double-breasted front with horn buttons. Two side pockets. Back vent for ease of movement. Dry clean only. Available in charcoal grey.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (33, 'en', 'RGB Mechanical Keyboard', 'Mechanical keyboard with Cherry MX switches, backlit', 'Cherry MX Brown switches for tactile feedback. Per-key RGB backlighting with 16.8 million colors. Aircraft-grade aluminum frame. Detachable USB-C cable. N-key rollover.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (34, 'en', 'Logitech Wireless Mouse', 'Ergonomic wireless mouse, 4000 DPI sensor', 'Advanced optical sensor, 400-4000 DPI adjustable. Ergonomic shape reduces wrist strain. 2.4GHz wireless or Bluetooth connectivity. 24-month battery life. Compatible with Windows, Mac, Linux.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (35, 'en', 'Sony Bluetooth Headphones', 'Wireless noise-cancelling headphones', 'Industry-leading Active Noise Cancellation. 30-hour battery life. LDAC Hi-Res Audio. Multipoint connection to 2 devices. Speak-to-Chat auto pause. 40mm drivers. Touch controls.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (36, 'en', 'HD Webcam 1080p', 'Full HD webcam with built-in microphone', '1920x1080 Full HD at 30fps. Built-in stereo microphone with noise reduction. Auto-focus and auto light correction. Universal clip mount. USB plug-and-play, no drivers needed.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (37, 'en', '1TB SSD Drive', 'NVMe M.2 SSD, 3500 MB/s read speed', 'PCIe Gen4 NVMe M.2 2280 form factor. Sequential read up to 3500 MB/s, write up to 3000 MB/s. TBW: 600TB. 5-year warranty. DRAM cache for sustained performance.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (38, 'en', 'JBL Bluetooth Speaker', 'Waterproof portable speaker, 12h battery', 'JBL Pro Sound with powerful bass. IP67 waterproof and dustproof. 12 hours playtime. PartyBoost for linking multiple speakers. Built-in strap. USB-C charging. Available in 6 colors.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (39, 'en', 'PlayStation 5', 'Next-gen gaming console with Blu-ray drive', 'Custom AMD Zen 2 CPU, 10.28 TFLOPS GPU. 825GB SSD with 5.5GB/s read speed. 4K gaming at up to 120fps. Ray tracing support. DualSense controller included. Backward compatible with PS4 games.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (40, 'en', 'PS5 DualSense Controller', 'Wireless controller with haptic feedback', 'Adaptive triggers with dynamic resistance. Haptic feedback for immersive sensation. Built-in microphone and speaker. USB-C charging. Up to 12 hours battery life. Available in multiple colors.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (41, 'en', 'Nintendo Switch OLED', 'Hybrid console with 7-inch OLED screen', '7-inch OLED screen with vivid colors. 64GB internal storage. Enhanced audio speakers. Wide adjustable stand. Wired LAN port in dock. Joy-Con controllers included.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (42, 'en', 'The Legend of Zelda: Tears of the Kingdom - Switch', 'Epic open-world adventure on Nintendo Switch', 'Explore the vast lands and skies of Hyrule. Build vehicles and weapons with the Ultrahand ability. New Fuse, Ascend, and Recall powers. Over 100 hours of content. The highest-rated game of 2023.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (43, 'en', 'EA FC 26 - PS5', 'Football simulation, World Cup edition on PlayStation 5', 'Official FIFA World Cup 2026 edition. HyperMotion V technology for realistic gameplay. 19,000+ players, 700+ teams, 100+ stadiums. Career mode, Ultimate Team, and online seasons.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (44, 'en', 'Razer Gaming Headset', '7.1 surround gaming headset with retractable mic', '50mm TriForce Titanium drivers. THX 7.1 Spatial Audio. Retractable boom microphone with noise isolation. Cooling gel-infused ear cushions. Lightweight 262g design.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (45, 'en', 'PSN Card 50€', 'PlayStation Network prepaid card 50€', 'Add 50€ to your PlayStation Network wallet. Use to buy games, DLCs, movies, and subscriptions. Compatible with PS4 and PS5. No expiration date. Digital delivery.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (46, 'en', 'Xbox Game Pass 3 Months', 'Xbox Game Pass Ultimate 3-month subscription', 'Access to 400+ games on console, PC, and cloud. Day one access to Xbox exclusives. EA Play membership included. Online multiplayer. Perks and discounts.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (47, 'en', 'Skip Liquid Detergent 2L', 'Concentrated liquid laundry detergent, 40 washes', 'Concentrated formula for effective cleaning. Works at 30°C for energy savings. Removes tough stains. Fresh scent. Suitable for all fabrics and colors.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (48, 'en', 'Ariel Pods x30', '3-in-1 laundry capsules, alpine freshness', 'Pre-dosed 3-in-1 capsules: cleaning, stain removal, and brightness. Alpine fresh scent. Works in cold water. Film dissolves completely. Simply toss in the drum.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (49, 'en', 'Fairy Dish Soap 1L', 'Ultra-degreasing dishwashing liquid', 'Ultra-concentrated formula cuts through grease instantly. One drop cleans a whole sink of dishes. Long-lasting suds. Gentle on hands. Effective even in cold water.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (50, 'en', 'Sponges x6', 'Pack of 6 multi-purpose scrubbing sponges', 'Dual-sided sponges: soft side for delicate surfaces, abrasive side for tough cleaning. Ergonomic shape. Quick-drying. Suitable for kitchen and bathroom.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (51, 'en', 'La Croix Bleach 2L', 'Disinfecting bleach', 'Concentrated sodium hypochlorite solution. Kills 99.9% of bacteria and viruses. Whitens fabrics. Disinfects surfaces. Dilute before use. Keep out of reach of children.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (52, 'en', 'Mr. Clean Multi-Surface', 'All-surface household cleaner, lemon', 'All-purpose cleaner for kitchen, bathroom, and floors. Fresh lemon scent. Cuts through grease and grime. No rinsing needed on most surfaces. Biodegradable formula.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (53, 'en', 'Trash Bags 50L x20', 'Heavy-duty trash bags with drawstring', '50-liter capacity, extra thick plastic. Drawstring closure for easy tying and carrying. Leak-proof bottom seal. Fits standard kitchen bins.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (54, 'en', 'Elsève Shampoo 300ml', 'Repairing shampoo for damaged hair', 'Enriched with keratin and ceramide. Repairs and strengthens damaged hair fiber. Restores shine and softness. Suitable for daily use. Dermatologically tested.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (55, 'en', 'Nivea Shower Gel 500ml', 'Moisturizing shower gel with almond oil', 'Enriched with sweet almond oil. Gently cleanses while moisturizing skin. pH skin-neutral formula. Dermatologically tested. Suitable for all skin types.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (56, 'en', 'Colgate Toothpaste 75ml', 'Whitening toothpaste with fluoride', 'Advanced whitening formula with micro-polishing particles. Fluoride protection against cavities. Freshens breath for up to 12 hours. Enamel-safe daily use.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (57, 'en', 'Dove Deodorant 200ml', '48h anti-perspirant deodorant', '48-hour protection against sweat and odor. 1/4 moisturizing cream. Alcohol-free formula. Dermatologically tested. Does not stain clothes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (58, 'en', 'Nivea Soft Cream 200ml', 'Light nourishing body moisturizer', 'The original Nivea Creme formula since 1911. Rich and nourishing texture. Suitable for face, body, and hands. Dermatologically tested. Contains Eucerit for deep moisturizing.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (59, 'en', 'Gillette Razors x4', 'Pack of 4 triple-blade disposable razors', '3 independently spring-mounted blades. Lubrication strip with aloe for smooth glide. Ergonomic rubber grip handle. Pivoting head follows facial contours.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (60, 'en', 'Lego City Fire Station', 'Lego City fire station set, 766 pieces', '766 pieces including fire station, truck, helicopter, and 5 minifigures. Ages 6+. Working garage door and helicopter landing pad. Compatible with all Lego City sets.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (61, 'en', 'Barbie Fashionista Doll', 'Barbie doll with fashion accessories', 'Fully articulated Barbie doll with trendy outfit. Includes shoes, bag, and sunglasses. Rooted hair for styling. Part of the Fashionistas diverse collection.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (62, 'en', '1000-Piece Puzzle', 'Mountain landscape puzzle, 1000 pieces', 'High-quality 1000-piece jigsaw puzzle. Finished size 70x50cm. Premium cardboard with linen finish to reduce glare. Precision-cut pieces for perfect fit. Ages 12+.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (63, 'en', 'Classic Monopoly', 'Classic board game, French edition', 'The classic property trading game since 1935. French edition with famous Paris streets. 2-8 players. Includes game board, tokens, cards, play money, dice, houses, and hotels.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (64, 'en', 'Plush Bear 40cm', 'Soft washable plush teddy bear', 'Ultra-soft polyester plush, 40cm tall. Hypoallergenic filling. Machine washable at 30°C. CE certified, safe for children from birth. Embroidered eyes for safety.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (65, 'en', 'Nerf Elite 2.0', 'Nerf blaster with 12 darts included', 'Fires darts up to 27 meters. Includes 12 official Nerf Elite foam darts. 6-dart internal clip. Slam-fire action for rapid blasting. Ages 8+.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (66, 'en', 'Hot Wheels Track Set', 'Car track set with loop and launcher', 'Includes motorized launcher and loop-the-loop. Compatible with all Hot Wheels cars. Easy snap-together assembly. Includes 1 Hot Wheels car. Ages 4+.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (1, 'fr', 'Pâtes Barilla 500g', 'Pâtes italiennes de qualité supérieure', 'Ingrédients : semoule de blé dur de qualité supérieure. Cuisson : 8-10 minutes. Tréfilage au bronze pour une meilleure adhérence des sauces. Fabriqué en Italie depuis 1877. Poids net : 500g. À conserver dans un endroit frais et sec.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (2, 'fr', 'Riz basmati 1kg', 'Riz basmati à grains longs, parfumé', 'Riz vieilli 12 mois pour un arôme optimal. Origine : piémonts de l''Himalaya. Chaque grain cuit de manière aérée et séparée. Idéal pour les currys, pilafs et sautés. Cuisson : 10-12 minutes dans 1.5 volume d''eau. Poids net : 1kg.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (3, 'fr', 'Huile d''olive vierge 1L', 'Huile d''olive extra vierge première pression à froid', 'Huile d''olive mono-variétale des oliveraies méditerranéennes. Acidité inférieure à 0.8%. Riche en antioxydants et polyphénols. Parfaite en salade, pour tremper le pain et en finition de plats. Extraction à froid. Bouteille en verre teinté pour préserver les arômes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (4, 'fr', 'Beurre doux Président 250g', 'Beurre doux de baratte Président, crémeux', 'Beurre de baratte traditionnel fabriqué à partir de crème pasteurisée. Matière grasse : 82%. Texture crémeuse et fondante. Idéal pour la pâtisserie, la cuisine et en tartine. Fabriqué en Normandie, France. À conserver entre 2°C et 6°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (5, 'fr', 'Farine de blé T55 1kg', 'Farine de blé tous usages', 'Farine de blé type 55, polyvalente pour tous usages. Taux de cendres : 0.50-0.60%. Parfaite pour le pain, les pâtisseries, les sauces et les pâtes à crêpes. Issue de blé français. Poids net : 1kg. À conserver à l''abri de l''humidité.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (6, 'fr', 'Sucre en poudre 1kg', 'Sucre blanc en poudre', 'Sucre blanc de canne, granulation fine. Se dissout rapidement et uniformément. Parfait pour la pâtisserie, les boissons chaudes et les desserts. Conditionné en France. Poids net : 1kg. Valeur énergétique : 400 kcal pour 100g.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (7, 'fr', 'Sel de Guérande 250g', 'Sel de mer récolté à la main', 'Sel de mer récolté à la main dans les marais salants de Guérande, en Bretagne. Naturellement gris, riche en minéraux et oligo-éléments (magnésium, calcium, potassium). Non raffiné et non lavé. Un incontournable de la gastronomie française. Poids net : 250g.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (8, 'fr', 'Oeufs bio x12', 'Oeufs biologiques de poules élevées en plein air', 'Oeufs de poules élevées en plein air avec accès à une alimentation biologique certifiée. Sans antibiotiques ni hormones. Jaunes d''un jaune intense au goût supérieur. Catégorie A, calibre M/L. Lot de 12. DCR : voir sur la boîte.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (9, 'fr', 'Evian 1.5L', 'Eau minérale naturelle des Alpes', 'Source des Alpes françaises, filtrée naturellement à travers les roches glaciaires pendant plus de 15 ans. Composition minérale équilibrée : calcium 80mg/L, magnésium 26mg/L, sodium 6.5mg/L. pH 7.2. Résidu sec : 309mg/L. Bouteille PET recyclable.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (10, 'fr', 'Perrier 1L', 'Eau minérale gazeuse naturelle', 'Eau minérale naturellement gazeuse depuis 1898, source de Vergèze dans le Gard. Bulles fines et persistantes. Zéro calorie. Minéralisation : calcium 155mg/L, sulfates 33mg/L. La bouteille verte iconique. Format 1L en verre.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (11, 'fr', 'Jus d''orange Tropicana 1L', 'Pur jus d''orange pressé, sans pulpe', '100% pur jus d''orange pressé, non issu de concentré. Sans sucres ajoutés. Riche en vitamine C (40mg pour 100ml, soit 50% des AJR). Pasteurisé pour garantir la fraîcheur. À consommer dans les 3 jours après ouverture. Brique de 1L.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (12, 'fr', 'Coca-Cola 1.5L', 'Boisson gazeuse rafraîchissante', 'La recette originale du cola depuis 1886. Ingrédients : eau gazéifiée, sucre, colorant caramel E150d, acidifiant acide phosphorique, arômes naturels dont caféine. Contient 10.6g de sucre pour 100ml. Servir bien frais à 4°C. Bouteille familiale 1.5L.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (13, 'fr', 'Limonade artisanale 75cl', 'Limonade artisanale au citron de Menton', 'Limonade artisanale élaborée à partir de citrons de Menton, récoltés à maturité sur la Côte d''Azur. Légèrement pétillante. Ingrédients 100% naturels : eau, jus de citron, sucre de canne. Sans colorants ni conservateurs artificiels. Bouteille en verre 75cl.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (14, 'fr', 'Eau de source Cristaline x6', 'Pack de 6 bouteilles d''eau de source 1.5L', 'Eau de source naturelle, légère et rafraîchissante. Pack pratique de 6 bouteilles de 1.5L pour toute la famille. Faible minéralisation (résidu sec < 200mg/L), adaptée à l''hydratation quotidienne et à la préparation des biberons. Bouteilles PET recyclables.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (15, 'fr', 'Thé glacé Lipton 1.5L', 'Thé glacé saveur pêche', 'Thé glacé rafraîchissant à la saveur pêche. Élaboré à partir de véritables feuilles de thé noir. Faible en calories (20 kcal/100ml). Ingrédients : eau, sucre, extrait de thé, arôme pêche, acidifiant acide citrique. Servir frais. Bouteille 1.5L.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (16, 'fr', 'Vin rouge Bordeaux 2020 75cl', 'Vin rouge AOC Bordeaux, fruité et équilibré', 'Assemblage Merlot (70%) et Cabernet Sauvignon (30%) de la rive droite de Bordeaux. Robe rubis profond. Nez de fruits rouges (cerise, framboise) et vanille. Bouche ronde et équilibrée aux tanins souples. Accompagne viandes rouges, fromages et charcuterie. Servir à 16-18°C. 13.5% vol.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (17, 'fr', 'Vin rouge Côtes du Rhône 2021 75cl', 'Vin rouge AOC, notes épicées et fruitées', 'Assemblage Grenache (60%) et Syrah (40%) du sud de la vallée du Rhône. Notes de mûre, poivre et herbes de garrigue. Corps puissant aux tanins soyeux. Idéal avec des grillades, du gibier ou des plats épicés. Servir à 16°C. 14% vol. Médaille d''or au Concours Général Agricole.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (18, 'fr', 'Champagne Moët & Chandon 75cl', 'Champagne brut Impérial, bulles fines', 'Le Moët Impérial, créé en 1869. Assemblage de Pinot Noir, Chardonnay et Pinot Meunier. Bulles fines et persistantes. Notes d''agrumes, de brioche et de fleurs blanches. Dosage brut. Vieillissement minimum 30 mois en cave. 12% vol. Parfait pour les célébrations. Servir entre 8 et 10°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (19, 'fr', 'Bière blonde Leffe 75cl', 'Bière d''abbaye blonde, douce et fruitée', 'Bière d''abbaye belge brassée depuis 1240 à l''abbaye de Leffe, près de Dinant. 6.6% vol. Refermentée en bouteille. Notes de vanille, clou de girofle et banane mûre. Robe dorée, mousse onctueuse. Servir à 5-6°C dans un verre calice. Format 75cl pour le partage.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (20, 'fr', 'Whisky Jameson 70cl', 'Irish whiskey triple distillation, doux et rond', 'Irish whiskey triple distillation, vieilli en fûts de chêne pendant minimum 4 ans. Robe dorée. Nez délicat de vanille, bois toasté et sherry. Bouche douce, légère et parfaitement équilibrée. 40% vol. Se déguste pur, avec des glaçons ou en cocktail (Irish Coffee, Whiskey Sour).');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (21, 'fr', 'Vin rosé Provence 2023 75cl', 'Vin rosé AOP Côtes de Provence, frais et léger', 'AOP Côtes de Provence. Assemblage Grenache, Cinsault et Syrah. Robe rose pâle saumonée. Arômes de pêche, agrumes et fleurs blanches. Bouche vive et rafraîchissante. Accompagne fruits de mer, salades et plats d''été. Servir entre 8 et 10°C. 12.5% vol.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (22, 'fr', 'Vin rouge Bourgogne Pinot Noir 2019 75cl', 'Vin rouge AOC Bourgogne, élégant et délicat', '100% Pinot Noir de la Côte de Beaune. Robe rubis clair. Arômes de cerise, framboise et chêne subtil. Tanins soyeux et finale longue. Accompagne volailles, champignons et fromages légers. Servir à 14-16°C. 12.5% vol. Élevé 12 mois en fûts de chêne français.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (23, 'fr', 'Veste en cuir noire', 'Veste en cuir véritable, coupe ajustée', 'Cuir d''agneau premium, souple et résistant. Fermetures éclair YKK, doublure 100% polyester. Coupe ajustée (slim fit). Deux poches extérieures zippées, une poche intérieure. Le cuir développera une belle patine avec le temps. Nettoyage : spécialiste cuir uniquement.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (24, 'fr', 'Jean slim Levi''s bleu', 'Jean slim stretch Levi''s confortable, bleu délavé', 'Composition : 98% coton, 2% élasthanne pour un confort stretch. Coupe slim à travers la hanche et la cuisse. 5 poches classiques. Lavable en machine à 30°C. Finition délavée bleu moyen. Rivets en métal renforcés. Braguette à boutons.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (25, 'fr', 'T-shirt coton blanc', 'T-shirt 100% coton bio, coupe droite', '100% coton biologique certifié GOTS. Grammage 180g/m² pour une bonne tenue. Col renforcé anti-déformation. Tissu pré-rétréci. Coupe droite unisexe. Disponible du XS au XXL. Lavable à 40°C. Fabriqué au Portugal dans des conditions de commerce équitable.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (26, 'fr', 'Pull en laine gris', 'Pull en laine mérinos, chaud et doux', '100% laine mérinos australienne, fibre 19.5 microns. Régulation naturelle de la température. Col rond, poignets et ourlet côtelés. Traitement anti-boulochage. Lavage à la main ou nettoyage à sec recommandé. Grammage 280g/m². Disponible du S au XXL.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (27, 'fr', 'Chemise en lin', 'Chemise en lin naturel, idéale pour l''été', '100% lin européen (fibre de lin cultivée en France et en Belgique). Respirant et absorbant l''humidité. Coupe regular avec col boutonné. Se bonifie à chaque lavage. Lavable en machine à 30°C. Parfaite pour les journées chaudes. Légères variations de texture naturelles du lin.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (28, 'fr', 'Blouson Schott cuir marron', 'Blouson Schott en cuir nubuck, style aviateur', 'Cuir nubuck premium, style aviateur inspiré des vestes de pilotes des années 40. Col en peau lainée amovible. Fermeture éclair frontale avec patte coupe-vent à boutons-pression. Deux poches à rabat. Doublure matelassée. Nettoyage spécialiste uniquement.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (29, 'fr', 'Robe d''été fleurie', 'Robe légère à motifs floraux, fluide', '100% viscose pour un tombé fluide et léger. Imprimé floral intégral aux couleurs vives. Col en V avec bretelles ajustables. Longueur midi (sous le genou). Lavable en machine à 30°C programme délicat. Parfaite pour la plage, les garden-parties et les sorties estivales.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (30, 'fr', 'Manteau d''hiver', 'Manteau long en laine mélangée, chaud et élégant', 'Composition : 70% laine, 30% polyester. Coupe longue croisée avec boutons en corne. Deux poches latérales profondes. Fente arrière pour faciliter la marche. Doublure intégrale. Nettoyage à sec uniquement. Disponible en gris anthracite. Un classique intemporel pour l''hiver.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (31, 'fr', 'MacBook Pro 14"', 'Ordinateur portable Apple M3 Pro, 18Go RAM, 512Go SSD', 'Puce Apple M3 Pro : CPU 11 coeurs (5 performance + 6 efficacité) et GPU 14 coeurs. 18 Go de mémoire unifiée. SSD 512 Go. Écran Liquid Retina XDR 14.2 pouces, résolution 3024x1964, ProMotion 120Hz. Autonomie jusqu''à 17 heures. Ports : MagSafe 3, 3x Thunderbolt 4/USB-C, HDMI 2.1, lecteur SD UHS-II, prise casque. Wi-Fi 6E, Bluetooth 5.3. Poids : 1.60 kg.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (32, 'fr', 'Écran 27" 4K', 'Moniteur IPS 4K UHD, 60Hz, HDR400', 'Dalle IPS 27 pouces, résolution 3840x2160 (4K UHD). Fréquence 60Hz. Précision colorimétrique 99% sRGB. Certifié HDR400. USB-C avec Power Delivery 65W. Pied réglable en hauteur, pivot et inclinaison. Compatible VESA 100x100mm. Haut-parleurs intégrés 2x 3W. 2x HDMI 2.0, 1x DisplayPort 1.4.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (33, 'fr', 'Clavier mécanique RGB', 'Clavier mécanique switches Cherry MX, rétroéclairé', 'Switches Cherry MX Brown : retour tactile sans clic audible. Rétroéclairage RGB par touche avec 16.8 millions de couleurs et effets personnalisables. Châssis en aluminium de qualité aéronautique. Câble USB-C détachable tressé. Anti-ghosting N-key rollover. Repose-poignet magnétique inclus. Touches PBT double-shot.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (34, 'fr', 'Souris sans fil Logitech', 'Souris ergonomique sans fil, capteur 4000 DPI', 'Capteur optique avancé, sensibilité réglable de 400 à 4000 DPI en 4 paliers. Forme ergonomique qui réduit la fatigue du poignet. Double connectivité : sans fil 2.4 GHz (récepteur nano USB) ou Bluetooth. Autonomie 24 mois avec une pile AA. Compatible Windows, macOS, Linux, ChromeOS. 5 boutons programmables.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (35, 'fr', 'Casque Bluetooth Sony', 'Casque sans fil à réduction de bruit active', 'Réduction de bruit active leader de l''industrie (processeur QN1). Autonomie 30 heures avec ANC activé. Audio Hi-Res LDAC et DSEE Extreme. Connexion multipoint simultanée à 2 appareils. Fonction Speak-to-Chat : pause automatique quand vous parlez. Transducteurs 40mm. Commandes tactiles. Poids : 254g. Étui de transport inclus.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (36, 'fr', 'Webcam HD 1080p', 'Webcam Full HD avec microphone intégré', 'Résolution Full HD 1920x1080 à 30 images/seconde. Microphone stéréo intégré avec réduction de bruit. Autofocus et correction automatique de luminosité. Clip de fixation universel compatible moniteurs et trépieds. USB plug-and-play, aucun pilote nécessaire. Compatible Zoom, Teams, Skype, Google Meet.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (37, 'fr', 'Disque dur SSD 1To', 'SSD NVMe M.2, vitesse lecture 3500 Mo/s', 'SSD NVMe PCIe Gen4 au format M.2 2280. Vitesse de lecture séquentielle jusqu''à 3500 Mo/s, écriture jusqu''à 3000 Mo/s. Endurance : 600 To écrits (TBW). Cache DRAM pour des performances soutenues. Contrôleur 4 canaux. Garantie 5 ans. Consommation : 5W en charge, 40mW en veille. Idéal pour le gaming et le montage vidéo.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (38, 'fr', 'Enceinte Bluetooth JBL', 'Enceinte portable waterproof, 12h d''autonomie', 'Son JBL Pro avec basses profondes et puissantes. Certification IP67 : étanche à l''eau et à la poussière. Autonomie 12 heures à volume modéré. Fonction PartyBoost pour connecter plusieurs enceintes ensemble. Sangle de transport intégrée. Charge USB-C (5h de charge complète). Puissance : 2x 10W. Bluetooth 5.1. Disponible en 6 coloris.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (39, 'fr', 'PlayStation 5', 'Console de jeu nouvelle génération, lecteur Blu-ray', 'CPU AMD Zen 2 personnalisé à 3.5 GHz, GPU RDNA 2 à 10.28 TFLOPS. SSD ultra-rapide 825 Go (5.5 Go/s en lecture). Jeux 4K jusqu''à 120fps. Ray tracing matériel. Sortie audio 3D Tempest Engine. Lecteur Blu-ray Ultra HD 4K. Manette DualSense avec retour haptique et gâchettes adaptatives incluse. Rétrocompatible avec 99% des jeux PS4.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (40, 'fr', 'Manette PS5 DualSense', 'Manette sans fil avec retour haptique', 'Gâchettes adaptatives avec résistance dynamique programmable. Retour haptique précis pour une sensation immersive. Microphone et haut-parleur intégrés. Charge USB-C. Autonomie jusqu''à 12 heures. Pavé tactile capacitif. Barre lumineuse. Prise casque 3.5mm. Gyroscope et accéléromètre 6 axes. Disponible en plusieurs coloris.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (41, 'fr', 'Nintendo Switch OLED', 'Console hybride avec écran OLED 7 pouces', 'Écran OLED 7 pouces aux couleurs vives et contrastes profonds. 64 Go de stockage interne (extensible via microSD). Haut-parleurs améliorés pour un son plus immersif. Béquille large et ajustable. Port LAN Ethernet intégré au dock. Manettes Joy-Con détachables. 3 modes de jeu : TV, sur table, portable.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (42, 'fr', 'The Legend of Zelda: Tears of the Kingdom - Switch', 'Aventure épique en monde ouvert sur Nintendo Switch', 'Explorez les vastes terres et ciels d''Hyrule dans cette suite épique. Construisez véhicules et armes grâce au pouvoir Emprise. Nouveaux pouvoirs : Fusion (combiner des objets), Infiltration (traverser la matière), Rétrospective (remonter le temps des objets). Plus de 100 heures de contenu. Note Metacritic : 96/100. Le jeu le mieux noté de 2023.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (43, 'fr', 'EA FC 26 - PS5', 'Simulation de football, édition Coupe du Monde sur PlayStation 5', 'Édition officielle Coupe du Monde FIFA 2026. Technologie HyperMotion V pour un gameplay réaliste basé sur la capture de mouvements réels. Plus de 19 000 joueurs, 700 équipes et 100 stades sous licence. Modes : Carrière, Ultimate Team, saisons en ligne, Volta Football. Cross-play entre plateformes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (44, 'fr', 'Casque gaming Razer', 'Casque gaming 7.1 surround, micro rétractable', 'Transducteurs TriForce Titanium 50mm pour un son clair et précis. Audio spatial THX 7.1. Microphone boom rétractable avec isolation des bruits. Coussinets à gel rafraîchissant pour un confort prolongé. Design ultra-léger de 262g. Câble tressé détachable 3.5mm. Compatible PC, PS5, Xbox, Switch.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (45, 'fr', 'Carte PSN 50€', 'Carte prépayée PlayStation Network 50€', 'Carte prépayée PlayStation Network d''une valeur de 50€. Créditez votre porte-monnaie PSN pour acheter des jeux, DLC, films et abonnements (PS Plus, PS Now). Compatible PS4 et PS5. Code à usage unique, sans date d''expiration. Livraison du code par email.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (46, 'fr', 'Xbox Game Pass 3 mois', 'Abonnement Xbox Game Pass Ultimate 3 mois', 'Abonnement Xbox Game Pass Ultimate de 3 mois. Accès à plus de 400 jeux sur console, PC et cloud (streaming). Accès Day One aux exclusivités Xbox. Abonnement EA Play inclus. Multijoueur en ligne. Avantages et réductions exclusifs sur le Microsoft Store.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (47, 'fr', 'Lessive liquide Skip 2L', 'Lessive liquide concentrée, 40 lavages', 'Lessive liquide concentrée pour 40 lavages. Formule active dès 30°C pour des économies d''énergie. Élimine les taches tenaces (graisse, herbe, sauce). Parfum frais longue durée. Convient à tous les textiles et toutes les couleurs. Doseur intégré. Bidon de 2L recyclable.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (48, 'fr', 'Lessive pods Ariel x30', 'Capsules de lessive 3-en-1, fraîcheur alpine', 'Capsules de lessive pré-dosées 3-en-1 : nettoyage en profondeur, détachage et éclat. Parfum fraîcheur alpine longue durée. Actives même à l''eau froide (20°C). Film hydrosoluble qui se dissout intégralement. Placer directement dans le tambour avant le linge. Boîte de 30 capsules. Tenir hors de portée des enfants.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (49, 'fr', 'Liquide vaisselle Fairy 1L', 'Liquide vaisselle ultra-dégraissant', 'Formule ultra-concentrée qui coupe la graisse instantanément. Une seule goutte suffit pour un évier entier de vaisselle. Mousse longue durée qui ne retombe pas. Doux pour les mains grâce à sa formule au pH neutre. Efficace même à l''eau froide. Flacon de 1L avec bouchon doseur.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (50, 'fr', 'Éponges x6', 'Lot de 6 éponges grattantes multi-usages', 'Lot de 6 éponges double face : côté doux pour les surfaces délicates (verre, céramique), côté abrasif vert pour le nettoyage intense (casseroles, plaques). Forme ergonomique pour une bonne prise en main. Séchage rapide. Convient pour la cuisine et la salle de bain.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (51, 'fr', 'Javel La Croix 2L', 'Eau de Javel désinfectante', 'Eau de Javel concentrée à base d''hypochlorite de sodium. Élimine 99.9% des bactéries et virus. Blanchit le linge blanc. Désinfecte les surfaces (plans de travail, sanitaires). Diluer avant utilisation (voir dosage au dos). Bidon de 2L. Tenir hors de portée des enfants. Ne pas mélanger avec d''autres produits ménagers.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (52, 'fr', 'Nettoyant multi-surfaces Mr Propre', 'Nettoyant ménager toutes surfaces, citron', 'Nettoyant ménager multi-surfaces au parfum citron frais. Efficace sur cuisine, salle de bain et sols. Coupe la graisse et élimine les salissures. Sans rinçage nécessaire sur la plupart des surfaces. Formule biodégradable. Flacon de 750ml avec spray. Convient pour le carrelage, l''inox, le verre et le plastique.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (53, 'fr', 'Sacs poubelle 50L x20', 'Sacs poubelle résistants avec liens coulissants', 'Sacs poubelle grande contenance 50 litres. Plastique extra-épais et résistant aux déchirures. Fermeture à liens coulissants pour un nouage facile et un transport propre. Joint de fond anti-fuites. S''adapte aux poubelles de cuisine standard. Lot de 20 sacs. Fabriqué à partir de plastique recyclé à 50%.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (54, 'fr', 'Shampooing Elsève 300ml', 'Shampooing réparateur pour cheveux abîmés', 'Shampooing réparateur enrichi en kératine et céramide. Répare et renforce la fibre capillaire fragilisée. Redonne brillance et douceur aux cheveux abîmés (colorations, lissages, sèche-cheveux). Convient à un usage quotidien. Testé dermatologiquement. Flacon de 300ml. Appliquer sur cheveux mouillés, masser et rincer.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (55, 'fr', 'Gel douche Nivea 500ml', 'Gel douche hydratant à l''huile d''amande', 'Gel douche hydratant enrichi à l''huile d''amande douce. Nettoie en douceur tout en hydratant la peau. Formule au pH neutre pour la peau. Testé dermatologiquement. Convient à tous les types de peau. Parfum délicat et apaisant. Grand format familial 500ml avec bouchon flip-top.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (56, 'fr', 'Dentifrice Colgate 75ml', 'Dentifrice blancheur avec fluor', 'Dentifrice blancheur avec micro-particules polissantes douces. Protection fluorée contre les caries (1450 ppm de fluorure). Rafraîchit l''haleine pendant 12 heures. Utilisation quotidienne sans risque pour l''émail. Tube de 75ml. Ingrédients actifs : monofluorophosphate de sodium, silice hydratée.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (57, 'fr', 'Déodorant Dove 200ml', 'Déodorant anti-transpirant 48h', 'Déodorant anti-transpirant offrant 48 heures de protection contre la transpiration et les odeurs. Contient 1/4 de crème hydratante. Formule sans alcool, douce pour la peau des aisselles. Testé dermatologiquement. Ne tache pas les vêtements. Spray aérosol de 200ml. Agiter avant utilisation.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (58, 'fr', 'Crème Nivea Soft 200ml', 'Crème hydratante nourrissante pour le corps', 'La crème Nivea originale, formulée depuis 1911. Texture riche et nourrissante à base d''Eucérite (émulsifiant breveté). Convient pour le visage, le corps et les mains. Hydrate intensément les peaux sèches. Testé dermatologiquement. Pot bleu iconique de 200ml. Sans parabènes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (59, 'fr', 'Rasoirs Gillette x4', 'Pack de 4 rasoirs jetables triple lame', 'Pack de 4 rasoirs jetables à triple lame. 3 lames montées indépendamment sur ressort pour épouser les contours du visage. Bande lubrifiante à l''aloe vera pour un rasage en douceur. Manche ergonomique avec grip en caoutchouc antidérapant. Tête pivotante pour les zones difficiles (menton, cou).');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (60, 'fr', 'Lego City Pompiers', 'Set Lego City caserne de pompiers, 766 pièces', 'Set Lego City comprenant la caserne de pompiers, un camion avec échelle, un hélicoptère et 5 figurines. 766 pièces. Âge recommandé : 6+. Porte de garage fonctionnelle et piste d''atterrissage pour hélicoptère. Compatible avec tous les sets Lego City. Instructions de montage étape par étape incluses. Dimensions de la caserne montée : 36x28x27 cm.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (61, 'fr', 'Poupée Barbie Fashionista', 'Poupée Barbie avec accessoires de mode', 'Poupée Barbie de la collection Fashionistas, célébrant la diversité. Entièrement articulée (14 points d''articulation). Tenue tendance avec chaussures, sac et lunettes de soleil. Cheveux enracinés coiffables. Fabriquée en plastique recyclable. Hauteur : 30 cm. Âge recommandé : 3+.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (62, 'fr', 'Puzzle 1000 pièces', 'Puzzle paysage de montagne, 1000 pièces', 'Puzzle de qualité supérieure de 1000 pièces représentant un paysage de montagne. Dimensions une fois terminé : 70x50 cm. Carton premium avec finition lin anti-reflets. Pièces découpées avec précision pour un assemblage parfait. Poster de référence inclus. Âge recommandé : 12+. Fabriqué en Europe.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (63, 'fr', 'Monopoly classique', 'Jeu de société classique, édition française', 'Le classique jeu de société d''achat et de vente de propriétés depuis 1935. Édition française avec les rues célèbres de Paris. De 2 à 8 joueurs. Contient : plateau de jeu, 8 pions, 28 cartes de propriété, 16 cartes Chance, 16 cartes Caisse de Communauté, billets de banque, 32 maisons, 12 hôtels et 2 dés. Durée de partie : 60 à 180 minutes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (64, 'fr', 'Peluche ours 40cm', 'Peluche ours en peluche douce, lavable', 'Peluche ours en polyester ultra-doux, hauteur 40 cm. Rembourrage hypoallergénique en fibres de polyester. Lavable en machine à 30°C (cycle délicat, filet de lavage recommandé). Certifié CE, sûr dès la naissance. Yeux brodés (non rapportés) pour la sécurité des tout-petits. Idéal comme compagnon de dodo.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (65, 'fr', 'Nerf Elite 2.0', 'Pistolet Nerf avec 12 fléchettes incluses', 'Pistolet Nerf de la gamme Elite 2.0. Portée de tir jusqu''à 27 mètres. Livré avec 12 fléchettes officielles Nerf Elite en mousse. Chargeur interne de 6 fléchettes. Action Slam-Fire pour un tir rapide en rafale. Fonctionne sans piles. Âge recommandé : 8+. Conforme aux normes de sécurité européennes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (66, 'fr', 'Circuit Hot Wheels', 'Circuit de voitures avec looping et lanceur', 'Circuit de voitures avec lanceur motorisé et looping spectaculaire. Montage facile par emboîtement (snap-together). Compatible avec toutes les voitures Hot Wheels (échelle 1:64). 1 voiture Hot Wheels incluse. Fonctionne avec 2 piles AA (non incluses). Âge recommandé : 4+. Dimensions du circuit monté : 80x40 cm.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (67, 'fr', 'Clair Obscur: Expedition 33 - PS5', 'RPG au tour par tour dans un monde onirique sur PlayStation 5', 'RPG au tour par tour développé par Sandfall Interactive. Explorez un monde peint à la main inspiré de la Belle Époque française. Système de combat innovant mêlant stratégie au tour par tour et actions en temps réel. Narration profonde et choix moraux impactant l''histoire. Graphismes sublimes sous Unreal Engine 5. Bande-son orchestrale. Durée de vie : 40-60 heures. Exclusivité console PlayStation 5.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (67, 'en', 'Clair Obscur: Expedition 33 - PS5', 'Turn-based RPG in a dreamlike world on PlayStation 5', 'Turn-based RPG developed by Sandfall Interactive. Explore a hand-painted world inspired by French Belle Époque. Innovative combat system blending turn-based strategy with real-time actions. Deep narrative with impactful moral choices. Stunning Unreal Engine 5 visuals. Orchestral soundtrack. 40-60 hours of gameplay.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (68, 'fr', 'Red Dead Redemption II - PS4', 'Aventure western en monde ouvert sur PlayStation 4', 'Chef-d''œuvre de Rockstar Games. Incarnez Arthur Morgan, hors-la-loi au crépuscule de l''ère du Far West, 1899. Monde ouvert immense et détaillé avec faune, flore et cycles météorologiques réalistes. Scénario principal de 60 heures avec des centaines d''heures de contenu annexe. Mode Red Dead Online inclus. Note Metacritic : 97/100. L''un des jeux les mieux notés de l''histoire.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (68, 'en', 'Red Dead Redemption II - PS4', 'Open-world western adventure on PlayStation 4', 'Rockstar Games'' masterpiece. Play as Arthur Morgan, an outlaw at the twilight of the Wild West era, 1899. Immense detailed open world with realistic wildlife, flora, and weather systems. 60-hour main story with hundreds of hours of side content. Red Dead Online included. Metacritic: 97/100.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (69, 'fr', 'Sekiro: Shadows Die Twice - Xbox One', 'Action-aventure exigeante dans le Japon féodal sur Xbox One', 'Jeu d''action-aventure de FromSoftware, créateurs de Dark Souls et Elden Ring. Japon de l''ère Sengoku revisité. Incarnez le Loup, un shinobi à la prothèse mécanique. Combats à l''épée nerveux et techniques, basés sur la posture et la parade. Bras prothétique avec outils interchangeables. Résurrection en combat. Gagnant du Game of the Year 2019. Note Metacritic : 91/100.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (69, 'en', 'Sekiro: Shadows Die Twice - Xbox One', 'Challenging action-adventure in feudal Japan on Xbox One', 'Action-adventure by FromSoftware, creators of Dark Souls and Elden Ring. Reimagined Sengoku-era Japan. Play as the Wolf, a shinobi with a mechanical prosthetic arm. Intense sword combat focused on posture and deflection. Interchangeable prosthetic tools. In-battle resurrection. Game of the Year 2019. Metacritic: 91/100.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (70, 'fr', 'Console Xbox One', 'Console de jeu Microsoft Xbox One, 1To', 'Console de jeu Microsoft Xbox One avec disque dur 1To. Processeur AMD Jaguar 8 cœurs à 1.75 GHz, GPU AMD Radeon à 1.31 TFLOPS. Lecteur Blu-ray intégré. Compatible avec la manette sans fil Xbox. Wi-Fi 802.11ac, Bluetooth, HDMI 2.0. Accès au Xbox Game Pass et au Xbox Live Gold. Rétrocompatible avec des centaines de jeux Xbox 360. Manette sans fil Xbox incluse.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (70, 'en', 'Xbox One Console', 'Microsoft Xbox One gaming console, 1TB', 'Microsoft Xbox One gaming console with 1TB hard drive. AMD Jaguar 8-core CPU at 1.75 GHz, AMD Radeon GPU at 1.31 TFLOPS. Built-in Blu-ray drive. Compatible with Xbox wireless controllers. Wi-Fi 802.11ac, Bluetooth, HDMI 2.0. Access to Xbox Game Pass and Xbox Live Gold. Backwards compatible with hundreds of Xbox 360 games. Wireless controller included.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (71, 'fr', 'Super Mario 3D All-Stars - Switch', 'Compilation de 3 jeux Mario classiques en 3D sur Nintendo Switch', 'Compilation de trois jeux Mario 3D légendaires optimisés pour la Nintendo Switch : Super Mario 64 (1996), Super Mario Sunshine (2002) et Super Mario Galaxy (2007). Graphismes remasterisés en haute résolution. Bandes-son originales incluses dans un lecteur audio intégré. Édition limitée. Des centaines d''heures de contenu à travers trois époques du jeu vidéo.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (71, 'en', 'Super Mario 3D All-Stars - Switch', 'Collection of 3 classic 3D Mario games on Nintendo Switch', 'Collection of three legendary 3D Mario games optimized for Nintendo Switch: Super Mario 64 (1996), Super Mario Sunshine (2002), and Super Mario Galaxy (2007). Remastered HD graphics. Original soundtracks included in a built-in music player. Limited edition. Hundreds of hours of content across three eras of gaming.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (72, 'fr', 'Glenfiddich 12 Ans Speyside Single Malt 70cl', 'Single malt scotch whisky vieilli 12 ans, 40%', 'Single malt emblématique du Speyside, distillé à Dufftown depuis 1887. Vieilli 12 ans en fûts de bourbon et de xérès Oloroso. Robe dorée. Nez de poire mûre, miel et chêne. Bouche douce et fruitée avec des notes de beurre et de crème. Finale longue et chaleureuse. 40% vol. Bouteille triangulaire iconique de 70cl.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (72, 'en', 'Glenfiddich 12 Year Old Speyside Single Malt 70cl', 'Single malt scotch whisky aged 12 years, 40%', 'Iconic Speyside single malt, distilled in Dufftown since 1887. Aged 12 years in bourbon and Oloroso sherry casks. Golden color. Nose of ripe pear, honey, and oak. Smooth, fruity palate with butterscotch notes. Long warm finish. 40% ABV. 70cl iconic triangular bottle.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (73, 'fr', 'Jack Daniel''s Old N°7 70cl', 'Tennessee whiskey charcoal mellowed, 40%', 'Tennessee whiskey produit à Lynchburg depuis 1866. Filtré goutte à goutte à travers 3 mètres de charbon d''érable (procédé Lincoln County). Vieilli en fûts de chêne blanc américain neufs carbonisés. Notes de caramel, vanille et bois toasté. Bouche douce et ronde. 40% vol. Le whiskey américain le plus vendu au monde.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (73, 'en', 'Jack Daniel''s Old No.7 70cl', 'Tennessee whiskey charcoal mellowed, 40%', 'Tennessee whiskey produced in Lynchburg since 1866. Drop by drop charcoal mellowed through 10 feet of sugar maple charcoal (Lincoln County Process). Aged in new charred American white oak barrels. Notes of caramel, vanilla, and toasted wood. Smooth and mellow. 40% ABV. The world''s best-selling American whiskey.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (74, 'fr', 'Vin blanc Sancerre 2022 75cl', 'Vin blanc AOC Sancerre, vif et minéral', '100% Sauvignon Blanc de la rive gauche de la Loire. Terroir argilo-calcaire de Sancerre. Robe jaune pâle aux reflets verts. Nez intense d''agrumes, buis et pierre à fusil. Bouche vive et minérale avec une belle longueur. Parfait avec les fromages de chèvre, fruits de mer et poissons. Servir entre 8 et 10°C. 13% vol.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (74, 'en', 'Sancerre White 2022', 'AOC Sancerre white wine, crisp and mineral', '100% Sauvignon Blanc from the left bank of the Loire. Clay-limestone terroir of Sancerre. Pale yellow with green highlights. Intense nose of citrus, boxwood, and gunflint. Crisp, mineral palate with great length. Perfect with goat cheese, seafood, and fish. Serve between 8 and 10°C. 13% ABV.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (75, 'fr', 'Vin blanc Riesling d''Alsace 2021 75cl', 'Vin blanc AOC Alsace, sec et aromatique', '100% Riesling d''Alsace, cépage noble roi de la région. Robe jaune clair brillante. Nez élégant de citron vert, fleurs blanches et pétrole subtil. Bouche sèche et tendue avec une acidité rafraîchissante. Grande pureté aromatique. Accompagne parfaitement la choucroute, les poissons et les coquillages. Servir à 8-10°C. 12.5% vol.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (75, 'en', 'Alsace Riesling 2021', 'AOC Alsace white wine, dry and aromatic', '100% Alsace Riesling, the noble king grape of the region. Bright pale yellow. Elegant nose of lime, white flowers, and subtle petrol. Dry, taut palate with refreshing acidity. Great aromatic purity. Perfect with sauerkraut, fish, and shellfish. Serve at 8-10°C. 12.5% ABV.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (76, 'fr', 'Vin blanc Chablis 2022 75cl', 'Vin blanc AOC Chablis, frais et minéral', '100% Chardonnay du vignoble de Chablis en Bourgogne. Terroir kimméridgien unique (calcaire fossilifère). Robe or pâle. Nez de citron, pomme verte et craie. Bouche fraîche et minérale, sans boisé (vinifié en cuve inox). Finale saline et persistante. Idéal avec huîtres, escargots et poissons grillés. Servir à 10-12°C. 12.5% vol.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (76, 'en', 'Chablis 2022', 'AOC Chablis white wine, fresh and mineral', '100% Chardonnay from the Chablis vineyard in Burgundy. Unique Kimmeridgian terroir (fossilized limestone). Pale gold color. Nose of lemon, green apple, and chalk. Fresh, mineral palate, unoaked (stainless steel). Saline, persistent finish. Ideal with oysters, snails, and grilled fish. Serve at 10-12°C. 12.5% ABV.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (77, 'fr', 'Vin rouge Haut-Médoc 2019 75cl', 'Vin rouge AOC Haut-Médoc, structuré et élégant', 'Assemblage Cabernet Sauvignon (60%) et Merlot (40%) du Haut-Médoc. Élevé 12 mois en barriques de chêne français (30% neuves). Robe grenat profond. Nez de cassis, cèdre et tabac blond. Bouche structurée avec des tanins fermes mais soyeux. Finale longue et épicée. Accompagne viandes rouges grillées et fromages affinés. Servir à 16-18°C. 13.5% vol.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (77, 'en', 'Haut-Médoc 2019', 'AOC Haut-Médoc red wine, structured and elegant', 'Cabernet Sauvignon (60%) and Merlot (40%) blend from Haut-Médoc. Aged 12 months in French oak barrels (30% new). Deep garnet color. Nose of blackcurrant, cedar, and blond tobacco. Structured palate with firm yet silky tannins. Long, spicy finish. Pairs with grilled red meats and aged cheeses. Serve at 16-18°C. 13.5% ABV.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (78, 'fr', 'Steak haché Charal 15% MG x4', 'Steaks hachés pur bœuf français, 4x125g', '100% pur bœuf origine France. 15% de matière grasse pour un goût généreux et juteux. 4 steaks hachés de 125g surgelés individuellement. Cuisson poêle : 3-4 minutes par face. Viande issue de races à viande françaises (Charolaise, Limousine). Sans conservateurs, sans colorants. À conserver au congélateur -18°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (78, 'en', 'Charal Beef Burgers 15% Fat x4', 'Pure French beef burgers, 4x125g', '100% pure beef, French origin. 15% fat for a generous, juicy taste. 4 individually frozen 125g burgers. Pan cooking: 3-4 minutes per side. From French beef breeds (Charolais, Limousin). No preservatives, no colorants. Store frozen at -18°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (79, 'fr', 'Poulet fermier Loué Label Rouge', 'Poulet fermier Loué élevé en plein air, ~1.5kg', 'Poulet fermier Loué certifié Label Rouge. Élevé en plein air avec accès au parcours herbeux pendant minimum 81 jours (contre 35 pour un poulet standard). Alimentation à base de céréales (70% minimum). Chair ferme et savoureuse. Poids moyen 1.5kg. Origine France garantie. Idéal rôti au four avec des herbes de Provence.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (79, 'en', 'Free-Range Label Rouge Chicken', 'Free-range chicken, ~1.5kg', 'Label Rouge certified free-range chicken. Raised outdoors with access to grassy runs for minimum 81 days (vs 35 for standard). Cereal-based feed (70% minimum). Firm, flavorful meat. Average weight 1.5kg. Guaranteed French origin. Ideal roasted with herbs.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (80, 'fr', 'Comté affiné 12 mois', 'Fromage Comté AOP, affiné en cave naturelle', 'Comté AOP du massif du Jura, affiné minimum 12 mois en cave naturelle. Lait cru de vaches Montbéliardes nourries à l''herbe. Pâte pressée cuite à la texture fondante. Arômes complexes de noisette grillée, fruits secs et caramel. Croûte naturelle frottée au sel. Idéal en plateau de fromages, fondue ou gratiné. Se conserve au réfrigérateur dans du papier sulfurisé.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (80, 'en', 'Comté Aged 12 Months', 'Comté AOP cheese, cave-aged', 'AOP Comté from the Jura mountains, aged minimum 12 months in natural caves. Raw milk from grass-fed Montbéliarde cows. Cooked pressed paste with melting texture. Complex flavors of toasted hazelnut, dried fruits, and caramel. Natural rubbed rind. Perfect on cheese boards, in fondue, or gratins.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (81, 'fr', 'Yaourt aux fruits Danone x4', 'Yaourts brassés aux fruits, 4x125g', 'Yaourts brassés aux fruits avec morceaux. 4 pots de 125g. Saveurs assorties : fraise, pêche, abricot, fruits rouges. Source de calcium et protéines. Lait origine France. Sans conservateurs artificiels. À conserver au réfrigérateur entre 2 et 6°C. À consommer jusqu''à la date indiquée sur l''opercule.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (81, 'en', 'Danone Fruit Yogurt x4', 'Stirred fruit yogurts, 4x125g', 'Stirred yogurts with real fruit pieces. 4x125g pots. Assorted flavors: strawberry, peach, apricot, mixed berries. Source of calcium and protein. French milk. No artificial preservatives. Refrigerate between 2 and 6°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (82, 'fr', 'Yaourt au chocolat Danone x4', 'Yaourts au chocolat onctueux, 4x125g', 'Yaourts au chocolat onctueux et gourmands. 4 pots de 125g. Préparés avec du vrai cacao. Texture crémeuse et douce. Source de calcium. Lait origine France. Sans colorants artificiels. Parfaits pour le goûter des enfants et des grands. À conserver au réfrigérateur entre 2 et 6°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (82, 'en', 'Danone Chocolate Yogurt x4', 'Creamy chocolate yogurts, 4x125g', 'Creamy, indulgent chocolate yogurts. 4x125g pots. Made with real cocoa. Smooth, gentle texture. Source of calcium. French milk. No artificial colorings. Perfect snack for kids and adults. Refrigerate between 2 and 6°C.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (83, 'fr', 'Nutella 750g', 'Pâte à tartiner aux noisettes et au cacao', 'La célèbre pâte à tartiner Ferrero, créée en 1964 en Italie. Ingrédients : sucre, huile de palme, noisettes (13%), cacao maigre (7.4%), lait écrémé en poudre (6.6%), lactosérum en poudre, lécithine de soja, vanilline. Pot en verre de 750g. Idéal sur des tartines, crêpes, gaufres ou en pâtisserie. À conserver à température ambiante.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (83, 'en', 'Nutella 750g', 'Hazelnut and cocoa spread', 'The famous Ferrero spread, created in 1964 in Italy. Ingredients: sugar, palm oil, hazelnuts (13%), fat-reduced cocoa (7.4%), skimmed milk powder (6.6%), whey powder, soy lecithin, vanillin. 750g glass jar. Perfect on toast, crêpes, waffles, or in baking. Store at room temperature.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (84, 'fr', 'Kinder Bueno x10', 'Barres chocolatées fourrées au lait et noisettes', 'Pack de 10 barres Kinder Bueno (5 sachets de 2 barres). Gaufrette croustillante enrobée de chocolat au lait Kinder, fourrée d''une crème onctueuse au lait et aux noisettes. Poids net : 430g. Parfait pour le goûter ou une pause gourmande. Fabriqué par Ferrero. À conserver dans un endroit frais et sec.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (84, 'en', 'Kinder Bueno x10', 'Milk and hazelnut chocolate bars', 'Pack of 10 Kinder Bueno bars (5 packs of 2). Crispy wafer coated in Kinder milk chocolate, filled with a smooth milk and hazelnut cream. Net weight: 430g. Perfect for snacking. Made by Ferrero. Store in a cool, dry place.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (85, 'fr', 'Brosse à dents Signal Medium', 'Brosse à dents medium avec nettoyeur de langue', 'Brosse à dents Signal à brins médium pour un nettoyage efficace au quotidien. Nettoyeur de langue intégré à l''arrière de la tête. Brins indicateurs de remplacement (décoloration = temps de changer). Manche ergonomique antidérapant. Tête compacte pour accéder aux zones difficiles. Recommandé par les dentistes. Changer tous les 3 mois.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (85, 'en', 'Signal Medium Toothbrush', 'Medium toothbrush with tongue cleaner', 'Signal medium-bristle toothbrush for effective daily cleaning. Built-in tongue cleaner on the back. Indicator bristles for replacement timing (fading = time to change). Ergonomic non-slip handle. Compact head to reach difficult areas. Dentist recommended. Replace every 3 months.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (86, 'fr', 'Aspirateur Dyson V15 Detect', 'Aspirateur balai sans fil avec détection laser', 'Aspirateur balai sans fil le plus puissant de Dyson. Technologie laser verte dans la brosse pour révéler la poussière microscopique invisible à l''œil nu. Écran LCD affichant en temps réel le nombre et la taille des particules aspirées. Moteur Hyperdymium à 125 000 tr/min. Autonomie jusqu''à 60 minutes. Filtration HEPA intégrale. Conversion en aspirateur à main. 14 cyclones générant 100 000 G de force centrifuge.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (86, 'en', 'Dyson V15 Detect Vacuum', 'Cordless stick vacuum with laser detection', 'Dyson''s most powerful cordless vacuum. Green laser technology in the cleaner head reveals microscopic dust invisible to the naked eye. LCD screen showing real-time particle count and size. Hyperdymium motor at 125,000 RPM. Up to 60 minutes runtime. Whole-machine HEPA filtration. Converts to handheld. 14 cyclones generating 100,000 G of centrifugal force.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (87, 'fr', 'Peluche Pokémon Pikachu 30cm', 'Peluche officielle Pokémon Pikachu, douce et câline', 'Peluche officielle sous licence The Pokémon Company. Pikachu, le Pokémon de type Électrik le plus célèbre du monde. Hauteur : 30 cm. Rembourrage 100% polyester hypoallergénique. Tissu ultra-doux au toucher velouté. Lavable en machine à 30°C (filet de lavage recommandé). Yeux brodés pour la sécurité des enfants. Âge recommandé : 3+. Certifié CE.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (87, 'en', 'Pokémon Pikachu Plush 30cm', 'Official Pokémon Pikachu plush, soft and cuddly', 'Official licensed plush by The Pokémon Company. Pikachu, the world''s most famous Electric-type Pokémon. Height: 30cm. 100% hypoallergenic polyester filling. Ultra-soft velvet-touch fabric. Machine washable at 30°C (wash bag recommended). Embroidered eyes for child safety. Ages 3+. CE certified.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (88, 'fr', 'Fanta Orange 1.5L', 'Boisson gazeuse à l''orange', 'Boisson gazeuse pétillante à l''orange de la marque Coca-Cola Company. Saveur orange fruitée et rafraîchissante. Bouteille PET de 1.5L. Ingrédients : eau gazéifiée, sucre, jus d''orange à base de concentré (5%), acidifiant (acide citrique), arômes naturels d''orange, stabilisant, colorant (caroténoïdes). À servir bien frais.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (88, 'en', 'Fanta Orange 1.5L', 'Orange flavored sparkling drink', 'Sparkling orange drink by The Coca-Cola Company. Fruity, refreshing orange flavor. 1.5L PET bottle. Ingredients: carbonated water, sugar, orange juice from concentrate (5%), citric acid, natural orange flavors, stabilizer, colorant (carotenoids). Serve chilled.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (89, 'fr', 'Sprite 1.5L', 'Boisson gazeuse au citron et citron vert', 'Boisson gazeuse limpide au citron et citron vert de la marque Coca-Cola Company. Goût vif et désaltérant sans colorant. Bouteille PET de 1.5L. Ingrédients : eau gazéifiée, sucre, acidifiant (acide citrique), arômes naturels de citron et citron vert, édulcorant (glycosides de stéviol). Idéal seul ou en cocktail.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (89, 'en', 'Sprite 1.5L', 'Lemon-lime sparkling drink', 'Clear lemon-lime sparkling drink by The Coca-Cola Company. Crisp, refreshing taste with no colorings. 1.5L PET bottle. Ingredients: carbonated water, sugar, citric acid, natural lemon and lime flavors, stevia sweetener. Great on its own or in cocktails.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (90, 'fr', 'Oasis Tropical 1.5L', 'Boisson aux fruits tropicaux', 'Boisson à base de jus de fruits tropicaux et d''eau de source. Mélange exotique de mangue, passion, goyave et ananas. Bouteille PET de 1.5L. Contient 12% de jus de fruits. Sans colorants artificiels. Source de vitamine C. À servir bien frais ou avec des glaçons. Marque du groupe Orangina Suntory.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (90, 'en', 'Oasis Tropical 1.5L', 'Tropical fruit drink', 'Tropical fruit juice drink with spring water. Exotic blend of mango, passion fruit, guava, and pineapple. 1.5L PET bottle. Contains 12% fruit juice. No artificial colorings. Source of vitamin C. Serve chilled or over ice. Brand of Orangina Suntory group.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (91, 'fr', 'Les Loups-Garous de Thiercelieux', 'Jeu de société d''ambiance pour 8 à 18 joueurs', 'Jeu de rôle et de déduction créé par Philippe des Pallières et Hervé Marly. Les villageois doivent identifier les loups-garous qui les dévorent chaque nuit. Rôles variés : voyante, sorcière, chasseur, cupidon. 8 à 18 joueurs. Durée : 20-40 min. Plus de 10 millions d''exemplaires vendus.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (91, 'en', 'The Werewolves of Miller''s Hollow', 'Party game for 8 to 18 players', 'Deduction and role-playing party game. Villagers must unmask werewolves. Various roles: seer, witch, hunter, cupid. 8-18 players. 20-40 min. Over 10 million copies sold worldwide.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (92, 'fr', 'Metal Gear Solid V: The Definitive Experience - PS4', 'Édition complète incluant Ground Zeroes et The Phantom Pain sur PS4', 'L''édition définitive de MGSV par Hideo Kojima. Ground Zeroes + The Phantom Pain + tout le DLC. Monde ouvert en Afghanistan et Afrique. Système Fulton. Mother Base à développer. Metal Gear Online inclus. Metacritic : 93/100.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (92, 'en', 'Metal Gear Solid V: The Definitive Experience - PS4', 'Complete edition with Ground Zeroes and The Phantom Pain on PS4', 'The definitive MGSV edition by Hideo Kojima. Ground Zeroes + The Phantom Pain + all DLC. Open world in Afghanistan and Africa. Fulton system. Mother Base to develop. Metal Gear Online included. Metacritic: 93/100.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (93, 'fr', 'Metal Gear Solid: Master Collection Vol.1 - PS5', 'Compilation MGS1 + MGS2 + MGS3 remasterisés sur PS5', 'La trilogie originale de Metal Gear Solid par Hideo Kojima. MGS1 (1998), MGS2: Sons of Liberty (2001), MGS3: Snake Eater (2004). Bonus : Metal Gear et Metal Gear 2 (MSX). Bandes dessinées numériques. Résolution et framerate améliorés PS5.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (93, 'en', 'Metal Gear Solid: Master Collection Vol.1 - PS5', 'MGS1 + MGS2 + MGS3 remastered on PS5', 'The original Metal Gear Solid trilogy by Hideo Kojima. MGS1, MGS2: Sons of Liberty, MGS3: Snake Eater. Bonus: MSX Metal Gear 1 & 2. Digital graphic novels. Enhanced resolution and framerate for PS5.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (94, 'fr', 'Hitman: World of Assassination - PS5', 'Trilogie complète Hitman en un seul jeu sur PS5', 'La trilogie Hitman complète. Agent 47, assassin d''élite. 20+ destinations : Paris, Dubaï, Dartmoor... Centaines d''approches par mission. Mode Freelancer roguelike. Ray tracing PS5.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (94, 'en', 'Hitman: World of Assassination - PS5', 'Complete Hitman trilogy in one game on PS5', 'The complete Hitman trilogy. Agent 47, elite assassin. 20+ destinations: Paris, Dubai, Dartmoor... Hundreds of approaches per mission. Freelancer roguelike mode. PS5 ray tracing.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (95, 'fr', 'Pokémon: Let''s Go, Pikachu - Switch', 'Aventure Pokémon revisitée dans la région de Kanto sur Switch', 'Revisitez Kanto avec Pikachu ! Basé sur Pokémon Jaune. Capture style Pokémon GO avec Joy-Con. 151 Pokémon + Alola + Meltan. Connectivité Pokémon GO. Coop local 2 joueurs. Compatible Poké Ball Plus.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (95, 'en', 'Pokémon: Let''s Go, Pikachu - Switch', 'Reimagined Pokémon adventure in Kanto on Switch', 'Revisit Kanto with Pikachu! Based on Pokémon Yellow. GO-style catching with Joy-Con. 151 Pokémon + Alolan forms + Meltan. Pokémon GO connectivity. Local 2-player co-op. Poké Ball Plus compatible.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (96, 'fr', 'PC Portable Dell XPS 16 9640', 'Intel Core Ultra 7, 16Go RAM, 512Go SSD, écran 16" OLED', 'Intel Core Ultra 7 155H (16 cœurs, 4.8 GHz). 16 Go LPDDR5x. SSD 512 Go. OLED 16" 3.2K 120Hz DCI-P3. Intel Arc. Thunderbolt 4 x2. Wi-Fi 7. Autonomie 13h. 2.0 kg. Aluminium CNC.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (96, 'en', 'Dell XPS 16 9640 Laptop', 'Intel Core Ultra 7, 16GB RAM, 512GB SSD, 16" OLED', 'Intel Core Ultra 7 155H (16 cores, 4.8 GHz). 16 GB LPDDR5x. 512 GB SSD. 16" OLED 3.2K 120Hz DCI-P3. Intel Arc. 2x Thunderbolt 4. Wi-Fi 7. 13h battery. 2.0 kg. CNC aluminum.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (97, 'fr', 'Apple iPhone 17 128Go Orange', 'Puce A19, écran 6.3" OLED, 128Go', 'Puce A19 3nm. OLED 6.3" 120Hz Always-On. 128 Go. Caméra 48 MP. Ultra grand-angle 48 MP. Face ID. USB-C. MagSafe. IP68. 5G. Coloris Orange. iOS 19.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (97, 'en', 'Apple iPhone 17 128GB Orange', 'A19 chip, 6.3" OLED, 128GB', 'A19 3nm chip. 6.3" OLED 120Hz Always-On. 128 GB. 48 MP camera. 48 MP ultra wide. Face ID. USB-C. MagSafe. IP68. 5G. Orange color. iOS 19.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (98, 'fr', 'Clean Architecture - Robert C. Martin', 'Guide de conception logicielle et architecture propre', 'Principes universels d''architecture logicielle : SOLID, composants, limites architecturales. Comment structurer du code flexible, maintenable et testable. Par Uncle Bob. 432 pages. Pearson.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (98, 'en', 'Clean Architecture - Robert C. Martin', 'Software design and clean architecture guide', 'Universal software architecture principles: SOLID, components, architectural boundaries. How to structure flexible, maintainable, testable code. By Uncle Bob. 432 pages. Pearson.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (99, 'fr', 'Domain-Driven Design - Eric Evans', 'Approche de la complexité au cœur du logiciel', 'Le livre fondateur du DDD. Bounded Context, Aggregate, Entity, Value Object, Repository, Ubiquitous Language. La référence pour les architectes logiciels. 560 pages. Addison-Wesley.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (99, 'en', 'Domain-Driven Design - Eric Evans', 'Tackling complexity in the heart of software', 'The foundational DDD book. Bounded Context, Aggregate, Entity, Value Object, Repository, Ubiquitous Language. The reference for software architects. 560 pages. Addison-Wesley.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (100, 'fr', 'Design Patterns - Gang of Four', 'Éléments de logiciels orientés objet réutilisables', '23 design patterns fondamentaux : Factory, Singleton, Observer, Strategy, Decorator, Adapter... Par Gamma, Helm, Johnson, Vlissides. Exemples C++ et Smalltalk. 416 pages. Addison-Wesley.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (100, 'en', 'Design Patterns - Gang of Four', 'Elements of reusable object-oriented software', '23 fundamental design patterns: Factory, Singleton, Observer, Strategy, Decorator, Adapter... By Gamma, Helm, Johnson, Vlissides. C++ and Smalltalk examples. 416 pages. Addison-Wesley.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (101, 'fr', 'OCP Java SE 21 Developer - Exam 1Z0-830', 'Guide de préparation à la certification Oracle Java 21', 'Records, sealed classes, pattern matching, virtual threads, sequenced collections. Exercices et questions d''examen. Par Boyarsky et Selikoff. 1000+ pages. Sybex/Wiley.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (101, 'en', 'OCP Java SE 21 Developer - Exam 1Z0-830', 'Oracle Java 21 certification prep guide', 'Records, sealed classes, pattern matching, virtual threads, sequenced collections. Practice exercises and mock exams. By Boyarsky and Selikoff. 1000+ pages. Sybex/Wiley.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (102, 'fr', 'Guide des mouvements de musculation - Frédéric Delavier', 'Approche anatomique de chaque exercice', '150+ exercices illustrés par des planches anatomiques. Tous les groupes musculaires. Conseils pour éviter les blessures. Traduit en 25+ langues. 192 pages. Vigot.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (102, 'en', 'Strength Training Anatomy - Frédéric Delavier', 'Anatomical approach to each exercise', '150+ exercises with detailed anatomical illustrations. All muscle groups. Injury prevention tips. Translated into 25+ languages. 192 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (103, 'fr', 'La méthode Delavier Vol.2 - Frédéric Delavier', 'Techniques avancées et programmes d''entraînement', '250 exercices avec variantes. Programmes split, full body, push/pull/legs. Nutrition et récupération. Co-écrit avec Michael Gundill. 256 pages. Vigot.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (103, 'en', 'Delavier''s Training Vol.2 - Frédéric Delavier', 'Advanced techniques and training programs', '250 exercises with variations. Split, full body, push/pull/legs programs. Nutrition and recovery. Co-written with Michael Gundill. 256 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (104, 'fr', 'Spider-Man : L''intégrale (T61) - Marvel', 'Intégrale Spider-Man, tome 61', 'Collection intégrale Spider-Man par Panini Comics. Réédition chronologique des comics Spider-Man. Tome 61. Couverture cartonnée. Format 17x26 cm.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (104, 'en', 'Spider-Man: Complete Collection (Vol.61) - Marvel', 'Spider-Man complete collection, volume 61', 'Complete Spider-Man collection by Panini Comics. Chronological reprint of Spider-Man comics. Volume 61. Hardcover. 17x26 cm format.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (105, 'fr', 'Spider-Man : L''intégrale 1990-1991 (T59) - Marvel', 'Intégrale Spider-Man 1990-1991', 'Les aventures de Spider-Man de 1990-1991. Période Todd McFarlane. Couverture cartonnée. Collection Panini Comics.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (105, 'en', 'Spider-Man: Complete Collection 1990-1991 (Vol.59) - Marvel', 'Spider-Man 1990-1991 complete collection', 'Spider-Man adventures from 1990-1991. Todd McFarlane era. Hardcover. Panini Comics collection.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (106, 'fr', 'Batman : Killing Joke - Alan Moore', 'Le chef-d''œuvre d''Alan Moore et Brian Bolland', 'L''un des plus grands comics jamais écrits. L''histoire d''origine du Joker par Alan Moore. Illustrations de Brian Bolland. Édition Urban Comics. Un récit sombre et psychologique sur la folie et le chaos. 64 pages. Inclut l''édition remasterisée.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (106, 'en', 'Batman: The Killing Joke - Alan Moore', 'The masterpiece by Alan Moore and Brian Bolland', 'One of the greatest comics ever written. The Joker''s origin story by Alan Moore. Art by Brian Bolland. A dark, psychological tale of madness and chaos. 64 pages. Includes remastered edition.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (107, 'fr', 'Spider-Man : Un jour nouveau - Dan Slott', 'Nouveau départ pour Spider-Man par Dan Slott', 'Après les événements de One More Day, Peter Parker repart à zéro. Par Dan Slott. Nouvelle dynamique pour le tisseur. Édition Panini Comics. Couverture cartonnée.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (107, 'en', 'Spider-Man: Brand New Day - Dan Slott', 'A fresh start for Spider-Man by Dan Slott', 'After One More Day, Peter Parker starts anew. By Dan Slott. New dynamics for the web-slinger. Panini Comics edition. Hardcover.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (108, 'fr', 'Batman : Un Long Halloween - Jeph Loeb', 'Enquête épique de Batman par Jeph Loeb et Tim Sale', 'Un tueur en série frappe à chaque fête. Batman, Harvey Dent et Jim Gordon mènent l''enquête. Par Jeph Loeb et Tim Sale. L''un des meilleurs comics Batman. Inspiration du film The Dark Knight. 384 pages. Édition Urban Comics.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (108, 'en', 'Batman: The Long Halloween - Jeph Loeb', 'Epic Batman mystery by Jeph Loeb and Tim Sale', 'A serial killer strikes on each holiday. Batman, Harvey Dent, and Jim Gordon investigate. By Jeph Loeb and Tim Sale. One of the best Batman comics. Inspiration for The Dark Knight film. 384 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (109, 'fr', 'L''investisseur intelligent - Benjamin Graham', 'Le guide classique de l''investissement en bourse', 'Le livre de référence en investissement, recommandé par Warren Buffett. Stratégie d''investissement value. Analyse fondamentale. Mr. Market. Marge de sécurité. Édition mise à jour avec commentaires de Jason Zweig. 640 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (109, 'en', 'The Intelligent Investor - Benjamin Graham', 'The classic guide to stock investing', 'The definitive investment book, recommended by Warren Buffett. Value investing strategy. Fundamental analysis. Mr. Market. Margin of safety. Updated edition with commentary by Jason Zweig. 640 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (110, 'fr', 'L''autoroute du millionnaire - MJ DeMarco', 'La voie express vers la richesse', 'Oubliez l''épargne passive et les fonds indiciels. MJ DeMarco présente la Fastlane : créer de la valeur, construire un business, générer des revenus passifs à grande échelle. Critique de la voie lente (travailler 40 ans). 400 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (110, 'en', 'The Millionaire Fastlane - MJ DeMarco', 'The fast lane to wealth', 'Forget passive saving and index funds. MJ DeMarco presents the Fastlane: create value, build a business, generate passive income at scale. Critique of the Slowlane (work 40 years). 400 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (111, 'fr', 'Père riche, père pauvre - Robert Kiyosaki', 'Ce que les riches enseignent à leurs enfants', 'Best-seller mondial sur l''éducation financière. Deux pères, deux visions de l''argent. Actifs vs passifs. Le cash-flow quadrant. L''importance de l''investissement immobilier et de l''entrepreneuriat. Plus de 40 millions d''exemplaires vendus. 336 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (111, 'en', 'Rich Dad Poor Dad - Robert Kiyosaki', 'What the rich teach their children about money', 'Global bestseller on financial education. Two dads, two views on money. Assets vs liabilities. Cash flow quadrant. Importance of real estate and entrepreneurship. Over 40 million copies sold. 336 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (112, 'fr', 'Le crime de l''Orient-Express - Agatha Christie', 'Le célèbre roman policier d''Hercule Poirot', 'Un meurtre à bord du mythique Orient-Express bloqué par la neige. Hercule Poirot mène l''enquête parmi 12 suspects. L''un des plus célèbres romans d''Agatha Christie. Publié en 1934. Adapté au cinéma en 1974 et 2017. Collection Livre de Poche.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (112, 'en', 'Murder on the Orient Express - Agatha Christie', 'The famous Hercule Poirot mystery', 'A murder aboard the legendary Orient Express stranded in snow. Hercule Poirot investigates 12 suspects. One of Agatha Christie''s most famous novels. Published 1934. Film adaptations in 1974 and 2017.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (113, 'fr', '1984 - George Orwell', 'Roman dystopique sur la surveillance et le totalitarisme', 'Dans un monde dominé par Big Brother, Winston Smith tente de résister au Parti. Novlangue, double-pensée, police de la pensée. L''un des romans les plus influents du XXe siècle. Publié en 1949. Prophétique sur la surveillance de masse. Collection Folio. 384 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (113, 'en', '1984 - George Orwell', 'Dystopian novel about surveillance and totalitarianism', 'In a world dominated by Big Brother, Winston Smith attempts to resist the Party. Newspeak, doublethink, thought police. One of the most influential novels of the 20th century. Published 1949. Prophetic about mass surveillance. 384 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (114, 'fr', 'Sherlock Holmes : L''Intégrale illustrée - Arthur Conan Doyle', 'L''intégrale des aventures de Sherlock Holmes', 'Toutes les aventures du célèbre détective de Baker Street. 4 romans et 56 nouvelles. Illustrations originales de Sidney Paget. Le chien des Baskerville, Le signe des quatre, Une étude en rouge... Édition de luxe reliée.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (114, 'en', 'Sherlock Holmes: The Complete Illustrated Collection - Arthur Conan Doyle', 'The complete Sherlock Holmes adventures', 'All adventures of the famous Baker Street detective. 4 novels and 56 short stories. Original Sidney Paget illustrations. The Hound of the Baskervilles, The Sign of the Four, A Study in Scarlet... Deluxe hardcover edition.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (115, 'fr', 'Le Petit Prince - Antoine de Saint-Exupéry', 'Conte philosophique et poétique universel', 'Le livre le plus traduit au monde après la Bible. L''histoire d''un petit prince voyageant de planète en planète. « On ne voit bien qu''avec le cœur. L''essentiel est invisible pour les yeux. » Illustrations originales de l''auteur. 96 pages. Éditions Gallimard.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (115, 'en', 'The Little Prince - Antoine de Saint-Exupéry', 'Universal philosophical and poetic tale', 'The most translated book in the world after the Bible. The story of a little prince traveling from planet to planet. "One sees clearly only with the heart. What is essential is invisible to the eye." Original illustrations by the author. 96 pages.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (116, 'fr', 'Harry Potter Coffret 7 livres - J.K. Rowling', 'L''intégrale des 7 tomes de la saga Harry Potter', 'Les 7 tomes de la saga Harry Potter en coffret : l''École des sorciers, la Chambre des Secrets, le Prisonnier d''Azkaban, la Coupe de Feu, l''Ordre du Phénix, le Prince de Sang-Mêlé, les Reliques de la Mort. Plus de 500 millions d''exemplaires vendus dans le monde. Éditions Gallimard Jeunesse.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (116, 'en', 'Harry Potter Complete Box Set - J.K. Rowling', 'All 7 books of the Harry Potter saga', 'All 7 Harry Potter books in one box set: Philosopher''s Stone, Chamber of Secrets, Prisoner of Azkaban, Goblet of Fire, Order of the Phoenix, Half-Blood Prince, Deathly Hallows. Over 500 million copies sold worldwide.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (117, 'fr', 'Dragon Ball Z - 1re partie - Tome 01 : Les Saïyens - Akira Toriyama', 'Le début de la saga Dragon Ball Z', 'Son Goku découvre ses origines extraterrestres lorsque son frère Raditz débarque sur Terre. Début de la saga des Saïyens. Par Akira Toriyama. Édition Glénat. Format poche. Sens de lecture japonais.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (117, 'en', 'Dragon Ball Z - Part 1 - Vol.01: The Saiyans - Akira Toriyama', 'The beginning of the Dragon Ball Z saga', 'Goku discovers his alien origins when his brother Raditz arrives on Earth. Start of the Saiyan saga. By Akira Toriyama. Japanese reading format.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (118, 'fr', 'Dragon Ball Z - 3e partie - Tome 03 : Le Super Saïyen/Freezer - Akira Toriyama', 'L''affrontement épique contre Freezer', 'Son Goku se transforme en Super Saïyen face à Freezer sur la planète Namek. L''un des moments les plus iconiques du manga. Par Akira Toriyama. Édition Glénat.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (118, 'en', 'Dragon Ball Z - Part 3 - Vol.03: Super Saiyan/Frieza - Akira Toriyama', 'The epic showdown against Frieza', 'Goku transforms into a Super Saiyan against Frieza on Planet Namek. One of manga''s most iconic moments. By Akira Toriyama.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (119, 'fr', 'Pack Naruto Tomes 1 + 2 + 3 - Masashi Kishimoto', 'Les 3 premiers tomes de Naruto', 'Naruto Uzumaki, jeune ninja porteur du démon renard à neuf queues, rêve de devenir Hokage. Découvrez les débuts du manga culte ! Équipe 7 : Naruto, Sasuke et Sakura. Par Masashi Kishimoto. Édition Kana. Pack de 3 tomes.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (119, 'en', 'Naruto Pack Volumes 1 + 2 + 3 - Masashi Kishimoto', 'The first 3 volumes of Naruto', 'Naruto Uzumaki, young ninja host of the Nine-Tailed Fox, dreams of becoming Hokage. Team 7: Naruto, Sasuke, and Sakura. By Masashi Kishimoto. 3-volume pack.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (120, 'fr', 'Hunter X Hunter - Tome 1 - Yoshihiro Togashi', 'Le début de l''aventure de Gon Freecss', 'Gon Freecss, 12 ans, part à la recherche de son père en passant l''examen de Hunter. Un manga culte de Yoshihiro Togashi (Yu Yu Hakusho). Système de Nen. Arcs narratifs complexes. Édition Kana.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (120, 'en', 'Hunter X Hunter - Volume 1 - Yoshihiro Togashi', 'The beginning of Gon Freecss''s adventure', 'Gon Freecss, age 12, searches for his father by taking the Hunter Exam. A cult manga by Yoshihiro Togashi (Yu Yu Hakusho). Nen system. Complex story arcs.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (121, 'fr', 'One Piece Édition originale Tome 01 - Eiichiro Oda', 'À l''aube d''une grande aventure', 'Monkey D. Luffy, garçon au corps élastique grâce au fruit du démon, rêve de devenir le Roi des Pirates. Le manga le plus vendu de l''histoire avec 500+ millions d''exemplaires. Par Eiichiro Oda. Édition originale Glénat.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (121, 'en', 'One Piece Original Edition Vol.01 - Eiichiro Oda', 'Romance Dawn - At the dawn of a great adventure', 'Monkey D. Luffy, a boy with rubber powers from a Devil Fruit, dreams of becoming the Pirate King. The best-selling manga in history with 500+ million copies. By Eiichiro Oda.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (122, 'fr', 'GTO Tome 1 - Tōru Fujisawa', 'Great Teacher Onizuka, le prof le plus déjanté', 'Eikichi Onizuka, 22 ans, ex-chef de gang, devient professeur. Son rêve : sortir avec une lycéenne... mais il finit par devenir le meilleur prof du lycée. Humour décapant et moments émouvants. Par Tōru Fujisawa. Édition Pika.');
INSERT INTO product_translations (product_id, locale, display_name, description, detailed_description) VALUES (122, 'en', 'GTO Volume 1 - Tōru Fujisawa', 'Great Teacher Onizuka, the craziest teacher', 'Eikichi Onizuka, 22, ex-gang leader, becomes a teacher. His dream: date a student... but he ends up becoming the best teacher in school. Sharp humor and touching moments. By Tōru Fujisawa.');
